        tasks = ['A', 'B', 'C', 'D']

        # Cost matrix: workers x tasks
        cost = {
            1: {'A': 9, 'B': 4, 'C': 3, 'D': 7},
            2: {'A': 4, 'B': 6, 'C': 5, 'D': 6},
            3: {'A': 5, 'B': 4, 'C': 7, 'D': 5},
