        x = model.addVars(
            workers, 
            tasks, 
            vtype=GRB.BINARY, 
            name="x"
        )

        # Set objective: minimize total working hours
        model.setObjective(
            gp.quicksum(
                cost[i][j] * x[i, j] 
                for i in workers 
                for j in tasks
            ), 
            GRB.MINIMIZE
        )

        # Constraints

